def process_order(order_data, db, email_service, logger):
    # Validate
    if not order_data.get('items'):
        return {'error': 'No items'}
    if not order_data.get('user_id'):
        return {'error': 'No user'}

    # Calculate total
    total = 0
    for item in order_data['items']:
        price = db.query(f"SELECT price FROM products WHERE id = {item['product_id']}")
        total += price * item['quantity']
        if item['quantity'] > 10:
            total -= price * item['quantity'] * 0.1

    # Save order
    order = db.query(f"INSERT INTO orders (user_id, total) VALUES ({order_data['user_id']}, {total}) RETURNING id")

    # Send email
    try:
        email_service.send(order_data['user_id'], f'Order {order.id} confirmed', f'Total: ${total}')
    except:
        logger.error('Email failed')

    return {'order_id': order.id, 'total': total}

